/**
 * @summary Process video for Reels format
 */
export const getProcessVideoUrl = () => {
  return `/api/video/process`;
};

export const processVideo = async (
  processVideoBody: ProcessVideoBody,
  options?: RequestInit,
): Promise<VideoResult> => {
  const formData = new FormData();
  if (processVideoBody.startTime !== undefined) {
    formData.append(`startTime`, processVideoBody.startTime.toString());
  }
  if (processVideoBody.endTime !== undefined) {
    formData.append(`endTime`, processVideoBody.endTime.toString());
  }
  if (processVideoBody.addCaptions !== undefined) {
    formData.append(`addCaptions`, processVideoBody.addCaptions.toString());
  }
  if (processVideoBody.convertToReels !== undefined) {
    formData.append(
      `convertToReels`,
      processVideoBody.convertToReels.toString(),
    );
  }

  return customFetch<VideoResult>(getProcessVideoUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

